import { Vpc } from 'aws-cdk-lib/aws-ec2';
import { App, CfnOutput, Duration, RemovalPolicy, Stack } from 'aws-cdk-lib';
import { ExpectedResult, IntegTest } from '@aws-cdk/integ-tests-alpha';
import {
  OntapDeploymentType,
  OntapFileSystem,
  OntapFileSystemSecret,
  OntapStorageVirtualMachine,
  OntapVolume,
  ThroughputCapacityPerHaPair,
  TieringPolicyName,
} from 'aws-cdk-lib/aws-fsx';

/*
 * Integration test for FSx for NetApp ONTAP using OntapFileSystemSecret.
 *
 * Validates that admin passwords generated by OntapFileSystemSecret are
 * accepted by both the file system (fsxAdminPassword) and the SVM
 * (svmAdminPassword), and that the file system reaches the AVAILABLE state.
 */
const app = new App();

const stack = new Stack(app, 'AwsCdkFsxOntapWithSecret');

const vpc = new Vpc(stack, 'VPC', {
  restrictDefaultSecurityGroup: false,
  maxAzs: 1,
});

const fsxAdminSecret = new OntapFileSystemSecret(stack, 'FsxAdminSecret');
fsxAdminSecret.applyRemovalPolicy(RemovalPolicy.DESTROY);

const svmAdminSecret = new OntapFileSystemSecret(stack, 'SvmAdminSecret');
svmAdminSecret.applyRemovalPolicy(RemovalPolicy.DESTROY);

const fileSystem = new OntapFileSystem(stack, 'OntapFileSystem', {
  vpc,
  vpcSubnets: [vpc.privateSubnets[0]],
  storageCapacityGiB: 1024,
  removalPolicy: RemovalPolicy.DESTROY,
  ontapConfiguration: {
    deploymentType: OntapDeploymentType.SINGLE_AZ_1,
    throughputCapacityPerHaPair: ThroughputCapacityPerHaPair.MB_PER_SEC_128,
    fsxAdminPassword: fsxAdminSecret.secretValueFromJson('password'),
    automaticBackupRetention: Duration.days(7),
  },
});

const svm = new OntapStorageVirtualMachine(stack, 'Svm', {
  fileSystem,
  name: 'secret_svm',
  svmAdminPassword: svmAdminSecret.secretValueFromJson('password'),
  removalPolicy: RemovalPolicy.DESTROY,
});

new OntapVolume(stack, 'Volume', {
  storageVirtualMachine: svm,
  name: 'secret_volume',
  sizeInBytes: 107374182400, // 100 GiB
  junctionPath: '/data',
  storageEfficiencyEnabled: true,
  tieringPolicy: {
    name: TieringPolicyName.SNAPSHOT_ONLY,
  },
  removalPolicy: RemovalPolicy.DESTROY,
});

new CfnOutput(stack, 'FileSystemId', { value: fileSystem.fileSystemId });
new CfnOutput(stack, 'FsxAdminSecretArn', { value: fsxAdminSecret.secretArn });
new CfnOutput(stack, 'SvmAdminSecretArn', { value: svmAdminSecret.secretArn });

const integ = new IntegTest(app, 'FsxOntapWithSecretIntegTest', {
  testCases: [stack],
});

// Validate the file system is created and reaches AVAILABLE state.
integ.assertions
  .awsApiCall('FSx', 'describeFileSystems', {
    FileSystemIds: [fileSystem.fileSystemId],
  })
  .expect(ExpectedResult.objectLike({
    FileSystems: [{
      FileSystemId: fileSystem.fileSystemId,
      FileSystemType: 'ONTAP',
      Lifecycle: 'AVAILABLE',
      OntapConfiguration: {
        DeploymentType: 'SINGLE_AZ_1',
      },
    }],
  }))
  .waitForAssertions({
    totalTimeout: Duration.minutes(60),
    interval: Duration.seconds(30),
  });

// Validate the SVM is created and reaches CREATED state.
integ.assertions
  .awsApiCall('FSx', 'describeStorageVirtualMachines', {
    StorageVirtualMachineIds: [svm.storageVirtualMachineId],
  })
  .expect(ExpectedResult.objectLike({
    StorageVirtualMachines: [{
      StorageVirtualMachineId: svm.storageVirtualMachineId,
      Name: 'secret_svm',
    }],
  }))
  .waitForAssertions({
    totalTimeout: Duration.minutes(30),
    interval: Duration.seconds(30),
  });
